import{i as e,r as t,s as n}from"./app-BCIsYiT8.js";import{t as r}from"./plugin-vue_export-helper-C2MVdOIS.js";var i=JSON.parse(`{"path":"/codex/12-codex-workflow-guide.html","title":"Codex 官方工作流指南","lang":"zh-CN","frontmatter":{"title":"Codex 官方工作流指南","order":12,"description":"Codex 官方工作流指南｜IDE/CLI/云端全场景标准化开发实践 Codex 的最佳使用方式是将其视为具备明确上下文感知能力的团队成员，通过清晰的任务描述、完整的上下文传递与可验证的完成标准，实现高效协同开发。本文基于 OpenAI 官方工作流文档，整理9 套标准化端到端工作流，覆盖代码解读、Bug 修复、测试编写、原型开发、迭代优化、云端重构、代...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Codex 官方工作流指南\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-05-10T05:28:08.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://vuepress-theme-hope-docs-demo.netlify.app/codex/12-codex-workflow-guide.html"}],["meta",{"property":"og:site_name","content":"小林学AI"}],["meta",{"property":"og:title","content":"Codex 官方工作流指南"}],["meta",{"property":"og:description","content":"Codex 官方工作流指南｜IDE/CLI/云端全场景标准化开发实践 Codex 的最佳使用方式是将其视为具备明确上下文感知能力的团队成员，通过清晰的任务描述、完整的上下文传递与可验证的完成标准，实现高效协同开发。本文基于 OpenAI 官方工作流文档，整理9 套标准化端到端工作流，覆盖代码解读、Bug 修复、测试编写、原型开发、迭代优化、云端重构、代..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-05-10T05:28:08.000Z"}],["meta",{"property":"article:modified_time","content":"2026-05-10T05:28:08.000Z"}]]},"git":{"createdTime":1777881193000,"updatedTime":1778390888000,"contributors":[{"name":"Yideng","username":"Yideng","email":"oointer@163.com","commits":3,"url":"https://github.com/Yideng"}]},"readingTime":{"minutes":7.2,"words":2160},"filePathRelative":"codex/12-codex-workflow-guide.md","autoDesc":true}`),a={name:`12-codex-workflow-guide.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="codex-官方工作流指南-ide-cli-云端全场景标准化开发实践" tabindex="-1"><a class="header-anchor" href="#codex-官方工作流指南-ide-cli-云端全场景标准化开发实践"><span>Codex 官方工作流指南｜IDE/CLI/云端全场景标准化开发实践</span></a></h1><p>Codex 的最佳使用方式是将其视为<strong>具备明确上下文感知能力的团队成员</strong>，通过清晰的任务描述、完整的上下文传递与可验证的完成标准，实现高效协同开发。本文基于 OpenAI 官方工作流文档，整理<strong>9 套标准化端到端工作流</strong>，覆盖代码解读、Bug 修复、测试编写、原型开发、迭代优化、云端重构、代码审查、文档更新全场景，同时明确 IDE 扩展、CLI、Codex Cloud 三种使用端的差异与最佳实践，新手可直接照搬使用。</p><h2 id="一、工作流通用基础规则" tabindex="-1"><a class="header-anchor" href="#一、工作流通用基础规则"><span>一、工作流通用基础规则</span></a></h2><h3 id="_1-1-核心协作原则" tabindex="-1"><a class="header-anchor" href="#_1-1-核心协作原则"><span>1.1 核心协作原则</span></a></h3><ul><li><p>所有工作流遵循<strong>目标 + 上下文 + 约束 + 完成标准</strong>四要素提示结构</p></li><li><p>明确 “完成定义”：Codex 需完成哪些校验、测试、检查才算任务结束</p></li><li><p>上下文传递：IDE 自动带入打开文件；CLI 需显式使用 <code>@文件路径</code> 或 <code>/mention</code> 附加文件</p></li></ul><h3 id="_1-2-终端差异速览" tabindex="-1"><a class="header-anchor" href="#_1-2-终端差异速览"><span>1.2 终端差异速览</span></a></h3><table><thead><tr><th>使用端</th><th>上下文优势</th><th>最佳场景</th></tr></thead><tbody><tr><td>IDE 扩展</td><td>自动加载打开文件，支持选中代码添加上下文</td><td>本地探索、快速修改、实时调试</td></tr><tr><td>CLI</td><td>支持完整会话记录、shell 命令联动</td><td>批量操作、复现脚本、任务转录</td></tr><tr><td>Codex Cloud</td><td>云端异步执行，不占用本地资源</td><td>长时间重构、批量任务、并行处理</td></tr></tbody></table><hr><h2 id="二、9-套官方标准工作流-含步骤-提示-验证" tabindex="-1"><a class="header-anchor" href="#二、9-套官方标准工作流-含步骤-提示-验证"><span>二、9 套官方标准工作流（含步骤 + 提示 + 验证）</span></a></h2><h3 id="工作流-1-代码库解读-新人上手-接手服务" tabindex="-1"><a class="header-anchor" href="#工作流-1-代码库解读-新人上手-接手服务"><span>工作流 1：代码库解读（新人上手 / 接手服务）</span></a></h3><p><strong>适用场景</strong>：新成员入职、接手现有服务、梳理请求流程 / 数据模型 / 协议<br><strong>适用端</strong>：IDE 扩展（最快）、CLI</p><h4 id="ide-扩展步骤" tabindex="-1"><a class="header-anchor" href="#ide-扩展步骤"><span>IDE 扩展步骤</span></a></h4><ol><li><p>打开核心相关文件</p></li><li><p>选中需分析的代码（可选但推荐）</p></li><li><p>输入提示词</p></li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>解释选中代码的请求流转流程，包含：</span></span>
<span class="line"><span>1. 涉及模块的职责摘要</span></span>
<span class="line"><span>2. 数据校验的位置与规则</span></span>
<span class="line"><span>3. 修改时需注意的 1-2 个坑点</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="4"><li>验证：要求输出结构化清单</li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>将请求流程总结为步骤列表，并列出所有涉及的文件</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="cli-步骤" tabindex="-1"><a class="header-anchor" href="#cli-步骤"><span>CLI 步骤</span></a></h4><ol><li><p>仓库根目录启动交互式会话：<code>codex</code></p></li><li><p>附加文件并输入提示</p></li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>读取 @foo.ts @schema.ts，解释服务使用的协议、Schema 与请求/响应流程，重点说明必填/可选字段与兼容规则</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><hr><h3 id="工作流-2-可复现-bug-修复" tabindex="-1"><a class="header-anchor" href="#工作流-2-可复现-bug-修复"><span>工作流 2：可复现 Bug 修复</span></a></h3><p><strong>适用场景</strong>：本地可复现的功能异常、逻辑错误<br><strong>适用端</strong>：CLI（闭环复现验证）、IDE 扩展</p><h4 id="cli-完整流程" tabindex="-1"><a class="header-anchor" href="#cli-完整流程"><span>CLI 完整流程</span></a></h4><ol><li><p>仓库根目录启动 Codex：<code>codex</code></p></li><li><p>提供完整复现步骤 + 约束</p></li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>Bug：设置页点击“保存”显示成功但数据未持久化</span></span>
<span class="line"><span>复现步骤：</span></span>
<span class="line"><span>1. 启动应用：npm run dev</span></span>
<span class="line"><span>2. 进入 /settings</span></span>
<span class="line"><span>3. 切换“启用提醒”开关</span></span>
<span class="line"><span>4. 点击保存</span></span>
<span class="line"><span>5. 刷新页面，开关恢复原状</span></span>
<span class="line"><span>约束：</span></span>
<span class="line"><span>- 不修改接口结构</span></span>
<span class="line"><span>- 最小化修改，尽可能补充回归测试</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>验证：修复后自动复现校验</li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>修复完成后，运行 lint 与最小化相关测试套件，返回命令与结果</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="ide-扩展流程" tabindex="-1"><a class="header-anchor" href="#ide-扩展流程"><span>IDE 扩展流程</span></a></h4><ol><li><p>打开可疑文件与调用方文件</p></li><li><p>输入提示</p></li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>找到导致“显示保存成功但未持久化”的 Bug，给出修复方案并说明 UI 验证方法</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><hr><h3 id="工作流-3-单元测试编写" tabindex="-1"><a class="header-anchor" href="#工作流-3-单元测试编写"><span>工作流 3：单元测试编写</span></a></h3><p><strong>适用场景</strong>：为函数 / 模块编写覆盖正常场景与边界情况的单元测试<br><strong>适用端</strong>：IDE 扩展（选中精准）、CLI</p><h4 id="ide-扩展步骤-1" tabindex="-1"><a class="header-anchor" href="#ide-扩展步骤-1"><span>IDE 扩展步骤</span></a></h4><ol><li><p>打开目标函数文件</p></li><li><p>选中函数代码，命令面板选择 <code>Add to Codex Thread</code></p></li><li><p>输入提示</p></li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>按照项目现有测试规范，为该函数编写单元测试</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="cli-步骤-1" tabindex="-1"><a class="header-anchor" href="#cli-步骤-1"><span>CLI 步骤</span></a></h4><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>为 @transform.ts 中的 invert_list 函数添加测试，覆盖正常场景与边界情况</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><hr><h3 id="工作流-4-截图转可运行-ui-原型" tabindex="-1"><a class="header-anchor" href="#工作流-4-截图转可运行-ui-原型"><span>工作流 4：截图转可运行 UI 原型</span></a></h3><p><strong>适用场景</strong>：基于设计截图 / 原型稿快速生成可运行页面<br><strong>适用端</strong>：CLI（图片附加）、IDE 扩展</p><h4 id="cli-步骤-2" tabindex="-1"><a class="header-anchor" href="#cli-步骤-2"><span>CLI 步骤</span></a></h4><ol><li><p>保存截图至本地（如 <code>./specs/ui.png</code>）</p></li><li><p>启动 Codex，拖拽图片附加到对话</p></li><li><p>输入提示</p></li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>根据截图创建仪表盘页面</span></span>
<span class="line"><span>约束：</span></span>
<span class="line"><span>- 使用 React+Vite+Tailwind，TypeScript 编写</span></span>
<span class="line"><span>- 严格匹配间距、排版、布局</span></span>
<span class="line"><span>交付物：</span></span>
<span class="line"><span>- 新页面路由与渲染代码</span></span>
<span class="line"><span>- 所需小组件</span></span>
<span class="line"><span>- 本地运行说明 README.md</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="4"><li>验证：要求启动服务并告知访问地址</li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>启动开发服务器，告知原型预览的本地 URL</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="ide-扩展步骤-2" tabindex="-1"><a class="header-anchor" href="#ide-扩展步骤-2"><span>IDE 扩展步骤</span></a></h4><ol><li><p>拖拽粘贴截图到 Codex 聊天</p></li><li><p>输入提示</p></li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>根据截图创建设置页面，遵循项目现有设计与样式规范</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><hr><h3 id="工作流-5-ui-实时迭代优化" tabindex="-1"><a class="header-anchor" href="#工作流-5-ui-实时迭代优化"><span>工作流 5：UI 实时迭代优化</span></a></h3><p><strong>适用场景</strong>：设计→调整→刷新→微调的快速视觉迭代<br><strong>适用端</strong>：CLI + 本地服务并行</p><h4 id="操作步骤" tabindex="-1"><a class="header-anchor" href="#操作步骤"><span>操作步骤</span></a></h4><ol><li><p>单独终端启动开发服务：<code>npm run dev</code></p></li><li><p>Codex 中输入优化指令</p></li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>为首页提出 2-3 项样式优化方案</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="3"><li>选定方向后精准迭代</li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>采用方案2，仅修改头部：</span></span>
<span class="line"><span>- 优化排版为编辑风格</span></span>
<span class="line"><span>- 增加间距</span></span>
<span class="line"><span>- 保证移动端适配</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="4"><li>验证：浏览器实时预览，确认后提交，回退需告知 Codex</li></ol><hr><h3 id="工作流-6-云端托管重构任务" tabindex="-1"><a class="header-anchor" href="#工作流-6-云端托管重构任务"><span>工作流 6：云端托管重构任务</span></a></h3><p><strong>适用场景</strong>：大型模块重构，本地规划 + 云端异步执行<br><strong>适用端</strong>：IDE（规划）→ Codex Cloud（执行）</p><h4 id="本地规划-ide" tabindex="-1"><a class="header-anchor" href="#本地规划-ide"><span>本地规划（IDE）</span></a></h4><ol><li><p>提交 / 暂存现有代码，保证对比干净</p></li><li><p>生成重构计划（可显式调用 <code>$plan</code> 技能）</p></li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>我们需要重构认证子系统，目标：</span></span>
<span class="line"><span>- 拆分职责（令牌解析/会话加载/权限控制）</span></span>
<span class="line"><span>- 减少循环引用</span></span>
<span class="line"><span>- 提升可测性</span></span>
<span class="line"><span>约束：</span></span>
<span class="line"><span>- 无用户可见行为变更</span></span>
<span class="line"><span>- 保持公共 API 稳定</span></span>
<span class="line"><span>- 输出分步迁移计划</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>审核并调整计划：明确文件迁移步骤 + 回滚方案</li></ol><h4 id="云端执行-ide→cloud" tabindex="-1"><a class="header-anchor" href="#云端执行-ide→cloud"><span>云端执行（IDE→Cloud）</span></a></h4><ol><li><p>选择云端环境</p></li><li><p>输入指令分步执行</p></li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>执行计划中的里程碑1</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="3"><li>审查云端 diff，完成后拉回本地或直接创建 PR</li></ol><hr><h3 id="工作流-7-本地代码审查" tabindex="-1"><a class="header-anchor" href="#工作流-7-本地代码审查"><span>工作流 7：本地代码审查</span></a></h3><p><strong>适用场景</strong>：提交 / PR 前的本地自检<br><strong>适用端</strong>：CLI</p><h4 id="操作步骤-1" tabindex="-1"><a class="header-anchor" href="#操作步骤-1"><span>操作步骤</span></a></h4><ol><li><p>启动 Codex：<code>codex</code></p></li><li><p>运行审查命令</p></li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>/review</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="3"><li>自定义审查焦点</li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>/review 重点检查边界情况与安全问题</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="4"><li>验证：根据反馈修复后重新审查</li></ol><hr><h3 id="工作流-8-github-pr-在线审查" tabindex="-1"><a class="header-anchor" href="#工作流-8-github-pr-在线审查"><span>工作流 8：GitHub PR 在线审查</span></a></h3><p><strong>适用场景</strong>：无需拉取分支，直接在线审查 PR<br><strong>适用端</strong>：GitHub（需提前开启 Codex Code Review）</p><h4 id="操作步骤-2" tabindex="-1"><a class="header-anchor" href="#操作步骤-2"><span>操作步骤</span></a></h4><ol><li><p>打开目标 GitHub PR</p></li><li><p>评论区标记 Codex 并指定审查方向</p></li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>@codex review</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>@codex review 审查安全漏洞与权限问题</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><hr><h3 id="工作流-9-项目文档更新" tabindex="-1"><a class="header-anchor" href="#工作流-9-项目文档更新"><span>工作流 9：项目文档更新</span></a></h3><p><strong>适用场景</strong>：修正 / 补充项目文档，保证准确可用<br><strong>适用端</strong>：IDE、CLI</p><h4 id="操作步骤-3" tabindex="-1"><a class="header-anchor" href="#操作步骤-3"><span>操作步骤</span></a></h4><ol><li><p>IDE 打开 / CLI <code>@</code> 指向文档文件</p></li><li><p>输入提示</p></li></ol><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-text"><span class="line"><span>更新“高级特性”文档，补充认证排查指南，校验所有链接有效性</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="3"><li>验证：查看渲染后的页面确认效果</li></ol><hr><h2 id="三、工作流串联最佳实践" tabindex="-1"><a class="header-anchor" href="#三、工作流串联最佳实践"><span>三、工作流串联最佳实践</span></a></h2><ol><li><p><strong>复杂任务拆分</strong>：先规划（工作流 6）→ 再开发 → 写测试（工作流 3）→ 审查（工作流 7）→ 文档（工作流 9）</p></li><li><p><strong>上下文复用</strong>：高频规范写入 <code>AGENTS.md</code>，避免重复说明</p></li><li><p><strong>必做验证</strong>：所有修改后必须运行校验、测试、审查，不直接合并未验证代码</p></li><li><p><strong>终端搭配</strong>：本地快速修改用 IDE，批量 / 脚本用 CLI，长时间任务用 Cloud</p></li></ol><hr><h2 id="四、通用验证方法-所有工作流通用" tabindex="-1"><a class="header-anchor" href="#四、通用验证方法-所有工作流通用"><span>四、通用验证方法（所有工作流通用）</span></a></h2><ol><li><p>代码修改：运行 <code>lint</code>/<code>type check</code>，审查 diff</p></li><li><p>功能修复：复现步骤验证，回归测试</p></li><li><p>文档更新：校验链接，预览渲染效果</p></li><li><p>重构任务：对比前后行为，保证无破坏性变更</p></li></ol><hr><h2 id="五、总结" tabindex="-1"><a class="header-anchor" href="#五、总结"><span>五、总结</span></a></h2><p>Codex 官方工作流的核心是<strong>标准化任务传递与结果校验</strong>，通过固定流程降低沟通成本、提升输出稳定性。无论个人快速开发还是团队协同，均可直接套用上述 9 套工作流，结合 IDE/CLI/Cloud 各自优势，让 Codex 真正成为可落地、可预期的开发协作伙伴。</p>`,101)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};